  assign GTEp75_cast = {insig_out1, 4'b0000};
  assign GTEp75_out1 = GTEp75_cast >= Point75_out1;



  assign alpha1st_or_4th_Quad_bool = LTEp25_out1 | GTEp75_out1;



  assign alpha1st_or_4th_Quad_out1 = {7'b0, alpha1st_or_4th_Quad_bool};



  always_ff @(posedge clk or posedge reset)
    begin : RAMDelayBalance_process
      if (reset == 1'b1) begin
        RAMDelayBalance_out1 <= 8'b00000000;
      end
      else begin
        RAMDelayBalance_out1 <= alpha1st_or_4th_Quad_out1;
      end
    end



  assign pow2switch_out1 = 1'b1;



  assign Point50_out1 = 17'b10000000000000000;



  assign p75mA_sub_cast = {15'b0, Point75_out1};
  assign p75mA_sub_cast_1 = {15'b0, {insig_out1, 4'b0000}};
  assign p75mA_sub_temp = p75mA_sub_cast - p75mA_sub_cast_1;
  assign p75mA_out1 = p75mA_sub_temp;



  assign Amp75_sub_cast = {15'b0, {insig_out1, 4'b0000}};
  assign Amp75_sub_cast_1 = {15'b0, Point75_out1};
  assign Amp75_sub_temp = Amp75_sub_cast - Amp75_sub_cast_1;
  assign Amp75_out1 = Amp75_sub_temp;



  assign Amp25_sub_cast = {15'b0, {insig_out1, 4'b0000}};
  assign Amp25_sub_cast_1 = {15'b0, Point25_out1};
  assign Amp25_sub_temp = Amp25_sub_cast - Amp25_sub_cast_1;
  assign Amp25_out1 = Amp25_sub_temp;



  assign p25mA_sub_cast = {15'b0, Point25_out1};
  assign p25mA_sub_cast_1 = {15'b0, {insig_out1, 4'b0000}};
  assign p25mA_sub_temp = p25mA_sub_cast - p25mA_sub_cast_1;
  assign p25mA_out1 = p25mA_sub_temp;



  assign LTEp50_cast = {insig_out1, 4'b0000};
  assign LTEp50_out1 = LTEp50_cast <= Point50_out1;



  assign QuadHandle1b_out1 = (GTEp75_out1 == 1'b0 ? p75mA_out1 :
              Amp75_out1);



  assign QuadHandle1b_out1_dtc = (QuadHandle1b_out1[31:17] != 15'b000000000000000 ? 13'b1111111111111 :
              QuadHandle1b_out1[16:4]);



  assign QuadHandle1a_out1 = (LTEp25_out1 == 1'b0 ? Amp25_out1 :
              p25mA_out1);



  assign QuadHandle1a_out1_dtc = (QuadHandle1a_out1[31:17] != 15'b000000000000000 ? 13'b1111111111111 :
              QuadHandle1a_out1[16:4]);



  assign QuadHandle2_out1 = (LTEp50_out1 == 1'b0 ? QuadHandle1b_out1_dtc :
              QuadHandle1a_out1_dtc);



  assign CastU16En1_out1 = QuadHandle2_out1;



  assign CastU16En3_out1 = {1'b0, CastU16En1_out1};



  assign CastU16En2_out1 = (CastU16En3_out1[13] != 1'b0 ? 13'b1111111111111 :
              CastU16En3_out1[12:0]);



  // saturation block maybe optimized away
  // if the NumDataPoints is a power of 2
  assign Saturation_out1 = (CastU16En2_out1 > 13'b0011111111111 ? 13'b0011111111111 :
              CastU16En2_out1);



  assign Switch_out1 = (pow2switch_out1 == 1'b0 ? CastU16En2_out1 :
              Saturation_out1);



  assign prelookup_idx = (Switch_out1 == 13'b0000000000000 ? 11'b00000000000 :
              (Switch_out1 >= 13'b0011111111111 ? 11'b11111111111 :
              Switch_out1[10:0]));



  assign Look_Up_Table_out1 = Look_Up_Table_data[prelookup_idx];



  always @(posedge clk)
    begin : Unit_Delay_process
      Unit_Delay_out1 <= Look_Up_Table_out1;
    end



  assign Negate_cast = {Unit_Delay_out1[16], Unit_Delay_out1};
  assign Negate_cast_1 =  - (Negate_cast);
  assign Negate_out1 = Negate_cast_1[16:0];



  assign Cosine_1 = (RAMDelayBalance_out1 == 8'b00000000 ? Negate_out1 :
              Unit_Delay_out1);



  assign Cosine_2 = Cosine_1;

  assign x = Cosine_2;

endmodule  // cosine

